data.query:
query WebhookSubscriptions($first: Int!, $after: String, $topics: [WebhookSubscriptionTopic!], $callbackUrl: URL) {
    webhookSubscriptions(first: $first, after: $after, topics: $topics, callbackUrl: $callbackUrl) {
        edges {
            node {
                id
                topic
                uri
                format
                createdAt
                updatedAt
                legacyResourceId
            }
            cursor
        }
        pageInfo {
            hasNextPage
            endCursor
        }
    }
}
